    19→  autoConnect?: boolean;
    20→  debugMode?: boolean;
    21→  useGlobalInstance?: boolean;
    22→  onConnect?: () => void;
    23→  onDisconnect?: (data: { reason: string; manual: boolean }) => void;
    24→  onError?: (error: any) => void;
