     8→import { EventEmitter } from 'events';
     9→
    10→// Mock EventSource for Server-Sent Events
    11→class EventSourceMock extends EventEmitter {
    12→  public readyState: number = 0;
    13→  public url: string;
    14→
    15→  public close = jest.fn();
    16→  public addEventListener = jest.fn();
    17→  public removeEventListener = jest.fn();
    18→
    19→  // EventSource constants
    20→  static readonly CONNECTING = 0;
    21→  static readonly OPEN = 1;
    22→  static readonly CLOSED = 2;
    23→
    24→  constructor(url: string, eventSourceInitDict?: EventSourceInit) {
    25→    super();
    26→    this.url = url;
    27→
    28→    // Setup mock behaviors
    29→    this.close.mockImplementation(() => {
    30→      this.readyState = EventSourceMock.CLOSED;
    31→      this.emit('close');
    32→    });
    33→
    34→    this.addEventListener.mockImplementation((type: string, listener: any) => {
    35→      this.on(type, listener);
    36→    });
    37→
    38→    this.removeEventListener.mockImplementation((type: string, listener: any) => {
    39→      this.off(type, listener);
    40→    });
    41→
    42→    // Simulate connection
    43→    process.nextTick(() => {
    44→      this.readyState = EventSourceMock.OPEN;
    45→      this.emit('open');
    46→    });
    47→  }
    48→
    49→  simulateMessage(data: any, eventType: string = 'message'): void {
    50→    this.emit(eventType, { data: JSON.stringify(data) });
    51→  }
    52→
    53→  simulateError(error: Error): void {
