    62→  debug: jest.fn(),
    63→  warn: jest.fn()
    64→};
    65→
    66→const mockClaudeInstanceService = {
    67→  getInstanceStatus: jest.fn(),
    68→  subscribeToEvents: jest.fn(),
    69→  unsubscribeFromEvents: jest.fn()
    70→};
    71→
    72→// Subject under test - WebSocket Event Stream Manager
    73→class WebSocketEventStreamManager {
    74→  private activeConnections: Map<string, WebSocketMock> = new Map();
    75→  private eventSources: Map<string, EventSourceMock> = new Map();
    76→  private instanceSubscriptions: Map<string, Set<string>> = new Map(); // instanceId -> userIds
    77→  private logger: any;
    78→  private claudeService: any;
    79→
    80→  constructor(logger: any, claudeService: any) {
    81→    this.logger = logger;
    82→    this.claudeService = claudeService;
    83→  }
    84→
    85→  async handleWebSocketConnection(ws: WebSocketMock, userId: string): Promise<void> {
    86→    const connectionId = `ws-${Date.now()}-${Math.random()}`;
    87→    this.activeConnections.set(connectionId, ws);
    88→
    89→    this.logger.info(`WebSocket connection established for user ${userId}`);
    90→
    91→    // Setup message handlers
    92→    ws.on('message', (data: any) => {
    93→      this.handleWebSocketMessage(connectionId, userId, data);
    94→    });
    95→
    96→    ws.on('close', () => {
    97→      this.handleWebSocketClose(connectionId, userId);
    98→    });
    99→
   100→    ws.on('error', (error: Error) => {
   101→      this.handleWebSocketError(connectionId, userId, error);
   102→    });
   103→
   104→    // Send welcome message
   105→    this.sendToWebSocket(ws, {
   106→      type: 'connection_established',
   107→      data: { connectionId, userId, timestamp: new Date() }
   108→    });
   109→  }
   110→
   111→  async subscribeToClaudeInstance(userId: string, instanceId: string): Promise<{ success: boolean; error?: string }> {
   112→    try {
   113→      this.logger.debug(`Subscribing user ${userId} to Claude instance ${instanceId}`);
   114→
   115→      // Verify instance exists
   116→      const instanceStatus = await this.claudeService.getInstanceStatus(instanceId);
   117→      if (!instanceStatus) {
   118→        return { success: false, error: 'Instance not found' };
   119→      }
   120→
   121→      // Add user to instance subscription
   122→      if (!this.instanceSubscriptions.has(instanceId)) {
   123→        this.instanceSubscriptions.set(instanceId, new Set());
   124→      }
   125→      this.instanceSubscriptions.get(instanceId)!.add(userId);
   126→
   127→      // Subscribe to Claude instance events if first subscriber
   128→      if (this.instanceSubscriptions.get(instanceId)!.size === 1) {
   129→        this.claudeService.subscribeToEvents(instanceId, (event: any) => {
   130→          this.handleClaudeInstanceEvent(instanceId, event);
   131→        });
   132→      }
   133→
   134→      // Setup Server-Sent Events connection
   135→      await this.setupEventSourceConnection(userId, instanceId);
   136→
   137→      this.logger.info(`User ${userId} subscribed to Claude instance ${instanceId}`);
   138→      return { success: true };
   139→
   140→    } catch (error: any) {
   141→      this.logger.error(`Failed to subscribe to instance: ${error.message}`);
   142→      return { success: false, error: error.message };
   143→    }
   144→  }
   145→
   146→  async unsubscribeFromClaudeInstance(userId: string, instanceId: string): Promise<void> {
   147→    this.logger.debug(`Unsubscribing user ${userId} from Claude instance ${instanceId}`);
   148→
   149→    const subscribers = this.instanceSubscriptions.get(instanceId);
   150→    if (subscribers) {
   151→      subscribers.delete(userId);
   152→
   153→      // If no more subscribers, unsubscribe from Claude events
   154→      if (subscribers.size === 0) {
   155→        this.claudeService.unsubscribeFromEvents(instanceId);
   156→        this.instanceSubscriptions.delete(instanceId);
   157→      }
   158→    }
   159→
   160→    // Close EventSource connection
   161→    const eventSourceKey = `${userId}-${instanceId}`;
   162→    const eventSource = this.eventSources.get(eventSourceKey);
   163→    if (eventSource) {
   164→      eventSource.close();
   165→      this.eventSources.delete(eventSourceKey);
   166→    }
   167→  }
   168→
   169→  broadcastToInstance(instanceId: string, message: any): void {
