   172→      this.logger.warn(`No subscribers for instance ${instanceId}`);
   173→      return;
   174→    }
   175→
   176→    this.logger.debug(`Broadcasting to ${subscribers.size} subscribers of instance ${instanceId}`);
   177→
   178→    // Broadcast via WebSocket to all active connections
   179→    this.activeConnections.forEach((ws, connectionId) => {
   180→      this.sendToWebSocket(ws, {
