   192→      const eventSourceKey = `${userId}-${instanceId}`;
   193→      const eventSource = this.eventSources.get(eventSourceKey);
   194→      if (eventSource) {
   195→        eventSource.simulateMessage({
   196→          instanceId,
   197→          event: message,
   198→          timestamp: new Date()
   199→        });
   200→      }
   201→    });
   202→  }
   203→
   204→  private async setupEventSourceConnection(userId: string, instanceId: string): Promise<void> {
   205→    const eventSourceKey = `${userId}-${instanceId}`;
   206→    const url = `/api/claude/instances/${instanceId}/events`;
   207→
   208→    const eventSource = new EventSourceMock(url);
   209→    this.eventSources.set(eventSourceKey, eventSource);
   210→
   211→    eventSource.on('open', () => {
   212→      this.logger.debug(`EventSource connection opened for ${eventSourceKey}`);
   213→    });
   214→
   215→    eventSource.on('error', (error: Error) => {
   216→      this.logger.error(`EventSource error for ${eventSourceKey}: ${error.message}`);
   217→    });
   218→
   219→    eventSource.on('close', () => {
   220→      this.logger.debug(`EventSource connection closed for ${eventSourceKey}`);
   221→      this.eventSources.delete(eventSourceKey);
   222→    });
